116: function Resolve-ExperimentProfilePath {
117:     param(
118:         [string]$ProfileName = "",
119:         [string]$ConfigPath = "config/experiment.example.json"
120:     )
121: 
122:     $config = Read-ExperimentConfig -ConfigPath $ConfigPath
123:     $paths = Get-ExperimentPaths -Config $config
124:     $profileReference = if ([string]::IsNullOrWhiteSpace($ProfileName)) {
125:         $config.runtime.defaultProfile
126:     }
127:     else {
128:         $ProfileName
129:     }
130: 
131:     if ([string]::IsNullOrWhiteSpace($profileReference)) {
132:         throw "Experiment runtime.defaultProfile must be configured before resolving a profile."
133:     }
134: 
135:     if ([System.IO.Path]::IsPathRooted($profileReference)) {
136:         return $profileReference
137:     }
138: 
139:     $isRelativePath = $profileReference.Contains([System.IO.Path]::DirectorySeparatorChar) `
140:         -or $profileReference.Contains([System.IO.Path]::AltDirectorySeparatorChar) `
141:         -or $profileReference.EndsWith(".json")
142:     if ($isRelativePath) {
143:         return Resolve-ExperimentPath -Path $profileReference
144:     }
145: 
146:     return (Join-Path $paths.profilesRoot "$profileReference.json")
147: }
