160:     $profileData = Get-Content -LiteralPath $resolvedProfilePath -Raw | ConvertFrom-Json
161:     Assert-ExperimentRequiredKeys -Context "Experiment profile" -Value $profileData -RequiredKeys @(
162:         "id",
163:         "target",
