165:         "environment",
166:         "prerequisites",
167:         "verification"
168:     )
169:     Assert-ExperimentRequiredKeys -Context "Experiment profile target" -Value $profileData.target -RequiredKeys @(
170:         "kind",
171:         "repositoryPath"
172:     )
173:     if ($profileData.PSObject.Properties.Name.Contains("source")) {
174:         Assert-ExperimentRequiredKeys -Context "Experiment profile source" -Value $profileData.source -RequiredKeys @(
175:             "kind",
176:             "repositoryUrl",
177:             "defaultBranch",
178:             "checkoutPath"
179:         )
180:     }
181:     elseif ($profileData.target.kind -eq "fixture") {
182:         Assert-ExperimentRequiredKeys -Context "Experiment fixture target" -Value $profileData.target -RequiredKeys @(
183:             "seedRoot"
184:         )
185:     }
186:     else {
187:         throw "Experiment profile '$($profileData.id)' must define either source metadata or a fixture target.seedRoot."
188:     }
189:     Assert-ExperimentRequiredKeys -Context "Experiment profile workspace" -Value $profileData.workspace -RequiredKeys @(
190:         "path"
191:     )
192:     Assert-ExperimentRequiredKeys -Context "Experiment profile environment" -Value $profileData.environment -RequiredKeys @(
193:         "required",
194:         "optional"
195:     )
196:     Assert-ExperimentRequiredKeys -Context "Experiment profile prerequisites" -Value $profileData.prerequisites -RequiredKeys @(
197:         "overlays"
198:     )
199:     if ($profileData.PSObject.Properties.Name.Contains("materializer")) {
200:         Assert-ExperimentRequiredKeys -Context "Experiment profile materializer" -Value $profileData.materializer -RequiredKeys @(
201:             "script"
202:         )
203:     }
204:     Assert-ExperimentRequiredKeys -Context "Experiment profile verification" -Value $profileData.verification -RequiredKeys @(
205:         "phases"
206:     )
207: 
208:     return $profileData
209: }
