211: function Normalize-ExperimentProfile {
212:     <#
213:     """Normalize a declarative experiment profile for either fixture or remote targets into immutable metadata: source checkout or fixture seed path, mutable target repo path, workspace path, optional materializer script, environment requirements, prerequisite overlays, and ordered verification phases. This helper defines discovery and validation only; downstream scripts perform cloning, installation, and verification without changing the profile shape."""
214:     #>
215:     param(
216:         [string]$ProfileName = "",
217:         [string]$ConfigPath = "config/experiment.example.json"
218:     )
219: 
220:     $config = Read-ExperimentConfig -ConfigPath $ConfigPath
221:     $entryScripts = Get-ExperimentEntryScripts -Config $config
222:     $profileData = Read-ExperimentProfile -ProfileName $ProfileName -ConfigPath $ConfigPath
223:     $repoRoot = Get-ExperimentRepoRoot
224: 
225:     $requiredEnvironment = @($profileData.environment.required)
226:     $optionalEnvironment = @($profileData.environment.optional)
227:     $prerequisiteOverlays = [ordered]@{}
228:     foreach ($property in $profileData.prerequisites.overlays.PSObject.Properties) {
229:         $prerequisiteOverlays[$property.Name] = $property.Value
230:     }
231: 
232:     $materializerScriptPath = $null
233:     if ($profileData.PSObject.Properties.Name.Contains("materializer")) {
234:         $materializerScriptPath = Resolve-ExperimentPath -Path $profileData.materializer.script
235:     }
236: 
237:     $normalizedPhases = @()
238:     foreach ($phase in @($profileData.verification.phases)) {
239:         Assert-ExperimentRequiredKeys -Context "Verification phase" -Value $phase -RequiredKeys @("id")
240: 
241:         $hasEntryScript = $phase.PSObject.Properties.Name.Contains("entryScript") -and -not [string]::IsNullOrWhiteSpace($phase.entryScript)
242:         $hasCommand = $phase.PSObject.Properties.Name.Contains("command") -and -not [string]::IsNullOrWhiteSpace($phase.command)
243:         if (-not $hasEntryScript -and -not $hasCommand) {
244:             throw "Verification phase '$($phase.id)' must define either entryScript or command."
245:         }
246: 
247:         $resolvedWorkingDirectory = if ($phase.PSObject.Properties.Name.Contains("workingDirectory") -and -not [string]::IsNullOrWhiteSpace($phase.workingDirectory)) {
248:             Resolve-ExperimentPath -Path $phase.workingDirectory
249:         }
250:         elseif ($hasEntryScript) {
251:             $repoRoot
252:         }
253:         else {
254:             throw "Verification phase '$($phase.id)' must set workingDirectory for direct commands."
255:         }
256: 
257:         $resolvedScriptPath = $null
258:         $phaseKind = if ($hasEntryScript) { "entryScript" } else { "command" }
259:         if ($hasEntryScript) {
260:             if (-not $entryScripts.PSObject.Properties.Name.Contains($phase.entryScript)) {
261:                 throw "Verification phase '$($phase.id)' references unknown entry script '$($phase.entryScript)'."
262:             }
263: 
264:             $resolvedScriptPath = $entryScripts.$($phase.entryScript)
265:         }
266: 
267:         $arguments = if ($phase.PSObject.Properties.Name.Contains("args")) {
268:             @($phase.args)
269:         }
270:         else {
271:             @()
272:         }
273: 
274:         $normalizedPhases += [pscustomobject]@{
275:             Id = $phase.id
276:             Kind = $phaseKind
277:             Description = if ($phase.PSObject.Properties.Name.Contains("description")) { $phase.description } else { $null }
278:             EntryScriptName = if ($hasEntryScript) { $phase.entryScript } else { $null }
279:             ScriptPath = $resolvedScriptPath
280:             Command = if ($hasCommand) { $phase.command } else { $null }
281:             Arguments = $arguments
282:             WorkingDirectory = $resolvedWorkingDirectory
283:             TimeoutSeconds = if ($phase.PSObject.Properties.Name.Contains("timeoutSeconds")) { [int]$phase.timeoutSeconds } else { $null }
284:         }
285:     }
286: 
287:     $resolvedSourceCheckoutPath = $null
288:     $normalizedSource = $null
289:     if ($profileData.PSObject.Properties.Name.Contains("source")) {
290:         $resolvedSourceCheckoutPath = Resolve-ExperimentPath -Path $profileData.source.checkoutPath
291:         $normalizedSource = [pscustomobject]@{
292:             Kind = $profileData.source.kind
293:             RepositoryUrl = $profileData.source.repositoryUrl
294:             DefaultBranch = $profileData.source.defaultBranch
295:             CheckoutPath = $resolvedSourceCheckoutPath
296:             SeedRoot = $null
297:         }
298:     }
299:     else {
300:         $resolvedSourceCheckoutPath = Resolve-ExperimentPath -Path $profileData.target.seedRoot
301:         $normalizedSource = [pscustomobject]@{
302:             Kind = $profileData.target.kind
303:             RepositoryUrl = $null
304:             DefaultBranch = $null
305:             CheckoutPath = $resolvedSourceCheckoutPath
306:             SeedRoot = $resolvedSourceCheckoutPath
307:         }
308:     }
309:     $resolvedTargetRepositoryPath = Resolve-ExperimentPath -Path $profileData.target.repositoryPath
310:     $resolvedWorkspacePath = Resolve-ExperimentPath -Path $profileData.workspace.path
311: 
312:     return [pscustomobject]@{
313:         Id = $profileData.id
314:         DisplayName = if ($profileData.PSObject.Properties.Name.Contains("displayName")) { $profileData.displayName } else { $profileData.id }
315:         Description = if ($profileData.PSObject.Properties.Name.Contains("description")) { $profileData.description } else { $null }
316:         ProfilePath = Resolve-ExperimentProfilePath -ProfileName $ProfileName -ConfigPath $ConfigPath
317:         Source = $normalizedSource
318:         SourceCheckoutPath = $resolvedSourceCheckoutPath
319:         Target = [pscustomobject]@{
320:             Kind = $profileData.target.kind
321:             RepositoryPath = $resolvedTargetRepositoryPath
322:             SeedRoot = if ($profileData.target.PSObject.Properties.Name.Contains("seedRoot")) {
323:                 Resolve-ExperimentPath -Path $profileData.target.seedRoot
324:             }
325:             else {
326:                 $null
327:             }
328:         }
329:         TargetRepositoryPath = $resolvedTargetRepositoryPath
330:         WorkspacePath = $resolvedWorkspacePath
331:         Materializer = if ($null -ne $materializerScriptPath) {
332:             [pscustomobject]@{
333:                 ScriptPath = $materializerScriptPath
334:             }
335:         }
336:         else {
337:             $null
338:         }
339:         MaterializerScriptPath = $materializerScriptPath
340:         Environment = [pscustomobject]@{
341:             Required = $requiredEnvironment
342:             Optional = $optionalEnvironment
343:         }
344:         RequiredEnvironmentVariables = $requiredEnvironment
345:         OptionalEnvironmentVariables = $optionalEnvironment
346:         PrerequisiteOverlays = [pscustomobject]$prerequisiteOverlays
347:         VerificationPhases = $normalizedPhases
348:         EntryScripts = $entryScripts
349:     }
350: }
