352: function Test-ExperimentPrerequisite {
353:     param(
354:         [Parameter(Mandatory = $true)]
355:         [string]$Name,
356: 
357:         [Parameter(Mandatory = $true)]
358:         $Definition
359:     )
360: 
361:     $commandInfo = Get-Command -Name $Definition.command -ErrorAction SilentlyContinue
362:     $minimumVersion = if ($Definition.PSObject.Properties.Name.Contains("minimumVersion")) {
363:         $Definition.minimumVersion
364:     }
365:     else {
366:         $null
367:     }
368: 
369:     return [pscustomobject]@{
370:         Name = $Name
371:         Command = $Definition.command
372:         Required = [bool]$Definition.required
373:         MinimumVersion = $minimumVersion
374:         IsAvailable = $null -ne $commandInfo
375:         CommandPath = if ($null -ne $commandInfo) { $commandInfo.Source } else { $null }
376:     }
377: }
378: 
379: function Assert-ExperimentPrerequisites {
380:     param(
381:         [Parameter(Mandatory = $true)]
382:         $Config
383:     )
384: 
385:     $failures = @()
386:     foreach ($property in $Config.prerequisites.PSObject.Properties) {
387:         $result = Test-ExperimentPrerequisite -Name $property.Name -Definition $property.Value
388:         if ($result.Required -and -not $result.IsAvailable) {
389:             $failures += $result
390:         }
391:     }
392: 
393:     if ($failures.Count -gt 0) {
394:         $missing = $failures | ForEach-Object { "$($_.Name) [$($_.Command)]" }
395:         throw "Missing required prerequisites: $($missing -join ', ')"
396:     }
397: }
